import{_ as i,o as l,c as t,ae as o}from"./chunks/framework.D9JM1nqk.js";const n="/UniversityCSI204/doc/assets/dev-home-headline.B-egRBEG.jpg",r="/UniversityCSI204/doc/assets/dev-diagram-use-case.drawio.CYIlfQ2h.svg",e="/UniversityCSI204/doc/assets/dev-diagram-class.drawio.DXRld7uW.svg",g=JSON.parse('{"title":"🏷️ โครงการเว็บไซต์ขายแผ่นและตลับเกม","description":"","frontmatter":{},"headers":[],"relativePath":"dev-home.md","filePath":"dev-home.md"}'),s={name:"dev-home.md"};function m(c,a,d,p,h,u){return l(),t("div",null,[...a[0]||(a[0]=[o('<p><img src="'+n+'" alt=""></p><blockquote><p>⚠☢💥 กิตนี้บังคับปล่อย (force push) เพื่อลองของใหม่ ๆ (แม้ว่ามันจะพัง) ผมจะไม่รับผิดชอบใด ๆ เลยนะถ้าระบบนี้ทำให้เกิดสงครามโลกครั้งที่ 3 ถือว่าเตือนแล้วนะ! -- iKla47</p></blockquote><h1 id="🏷️-โครงการเว็บไซต์ขายแผ่นและตลับเกม" tabindex="-1">🏷️ โครงการเว็บไซต์ขายแผ่นและตลับเกม <a class="header-anchor" href="#🏷️-โครงการเว็บไซต์ขายแผ่นและตลับเกม" aria-label="Permalink to &quot;🏷️ โครงการเว็บไซต์ขายแผ่นและตลับเกม&quot;">​</a></h1><p>เราเป็นระบบร้านค้าสำหรับการขายแผ่นเกม (Game Disc) และตลับ (Game Cartridge) ที่เราได้รวบรวมจากแหล่งต่าง ๆ ทั่วทุกมุมโลก และทุกแนวเกมที่เป็นไปได้ไม่ว่าจะเป็นเกมเล่นในครอบครัว, เกมผ่านด่าน, เกมเนื้อเรื่อง, เกมยิงปืน, หรือเกมอะไรก็ตามจากทุกยุค-ทุกสมัย ทั้งหมดนี้ถูกสร้างขึ้นด้วยใจรักจากกลุ่มนักศึกษาทั้ง 5 คน:</p><ul><li>67168514 ปิยะบุตร อิ่มทอง - <a href="https://github.com/iKla47" target="_blank" rel="noreferrer">iKla47</a></li><li>67163266 สิรภพ อ่วมแก้ว - <a href="https://github.com/SiRaCCC" target="_blank" rel="noreferrer">SiRaCCC</a></li><li>(รหัสนักศึกษา) (ชื่อ-นามสกุล) - (ลิงค์กิต)</li><li>(รหัสนักศึกษา) (ชื่อ-นามสกุล) - (ลิงค์กิต)</li><li>(รหัสนักศึกษา) (ชื่อ-นามสกุล) - (ลิงค์กิต)</li></ul><h2 id="หลักการและเหตุผล-relationable" tabindex="-1">หลักการและเหตุผล (Relationable) <a class="header-anchor" href="#หลักการและเหตุผล-relationable" aria-label="Permalink to &quot;หลักการและเหตุผล (Relationable)&quot;">​</a></h2><p><em>(ประโยคตัวอย่าง)</em></p><h2 id="วัตถุประสงค์ของโครงงาน-objectives" tabindex="-1">วัตถุประสงค์ของโครงงาน (Objectives) <a class="header-anchor" href="#วัตถุประสงค์ของโครงงาน-objectives" aria-label="Permalink to &quot;วัตถุประสงค์ของโครงงาน (Objectives)&quot;">​</a></h2><p>พวกเราในฐานะเติบโตมาพร้อมกับเกมหลายยุค-หลายสมัย จุดประงสงค์ของเราต้องการที่จะ:</p><ul><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li></ul><h2 id="ขอบเขตของระบบ-system-scope" tabindex="-1">ขอบเขตของระบบ (System Scope) <a class="header-anchor" href="#ขอบเขตของระบบ-system-scope" aria-label="Permalink to &quot;ขอบเขตของระบบ (System Scope)&quot;">​</a></h2><p>ระบบมีผู้ใช้งานหลัก (Actor) อยู่ 3 บุคคล:</p><ul><li><code>ผู้ใช้ทั่วไป</code></li><li><code>ผู้สมัครสมาชิก</code></li><li><code>ผู้ดูแลระบบ</code></li></ul><p>ความสามารถหลักของระบบ (Main Functions)</p><ol><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li><li><em>(ประโยคตัวอย่าง)</em></li></ol><h2 id="แนวทางการพัฒนาตาม-sdlc-system-development-life-cycle" tabindex="-1">แนวทางการพัฒนาตาม SDLC (System Development Life Cycle) <a class="header-anchor" href="#แนวทางการพัฒนาตาม-sdlc-system-development-life-cycle" aria-label="Permalink to &quot;แนวทางการพัฒนาตาม SDLC (System Development Life Cycle)&quot;">​</a></h2><h3 id="_1-การวางแผน-planning" tabindex="-1">1. การวางแผน (Planning) <a class="header-anchor" href="#_1-การวางแผน-planning" aria-label="Permalink to &quot;1. การวางแผน (Planning)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_2-การวิเคราะห์-analysis" tabindex="-1">2. การวิเคราะห์ (Analysis) <a class="header-anchor" href="#_2-การวิเคราะห์-analysis" aria-label="Permalink to &quot;2. การวิเคราะห์ (Analysis)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_3-การออกแบบ-design" tabindex="-1">3. การออกแบบ (Design) <a class="header-anchor" href="#_3-การออกแบบ-design" aria-label="Permalink to &quot;3. การออกแบบ (Design)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_4-การพัฒนา-development" tabindex="-1">4. การพัฒนา (Development) <a class="header-anchor" href="#_4-การพัฒนา-development" aria-label="Permalink to &quot;4. การพัฒนา (Development)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_5-การทดสอบ-testing" tabindex="-1">5. การทดสอบ (Testing) <a class="header-anchor" href="#_5-การทดสอบ-testing" aria-label="Permalink to &quot;5. การทดสอบ (Testing)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_6-การติดตั้ง-deployment" tabindex="-1">6. การติดตั้ง (Deployment) <a class="header-anchor" href="#_6-การติดตั้ง-deployment" aria-label="Permalink to &quot;6. การติดตั้ง (Deployment)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="_7-การบํารุงรักษา-maintenance" tabindex="-1">7. การบำรุงรักษา (Maintenance) <a class="header-anchor" href="#_7-การบํารุงรักษา-maintenance" aria-label="Permalink to &quot;7. การบำรุงรักษา (Maintenance)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h2 id="🛠️-เครื่องมือและเทคโนโลยี-tools-technologies" tabindex="-1">🛠️ เครื่องมือและเทคโนโลยี (Tools &amp; Technologies) <a class="header-anchor" href="#🛠️-เครื่องมือและเทคโนโลยี-tools-technologies" aria-label="Permalink to &quot;🛠️ เครื่องมือและเทคโนโลยี (Tools &amp; Technologies)&quot;">​</a></h2><p><em>(รายการนี้สถานะไม่คงที่ และอาจเปลี่ยนแปลงได้ในอนาคต)</em></p><ul><li><p>ส่วนหน้า (Frontend)</p><ul><li>NodeJS: รันไทม์สำหรับภาษาโปรแกรม JavaScript (ใช้ระหว่างพัฒนา)</li><li>TypeScript: ภาษาเพิ่มเติมจาก JavaScript ที่ช่วยจับข้อผิดพลาดผ่าน Type-Checking และ Interface</li><li>Vite: เครื่องมือในการสร้างเว็บไซต์และรันเซิร์ฟเวอร์ในระหว่างการพัฒนา (Development Server)</li><li>React: ไลบรารีอำนวยความสะดวกในการสร้าง UI ผ่านแนวคิดส่วนประกอบ (Component)</li><li>Styled Components: อำนวยความสะดวกในการใช้งาน CSS ร่วมกับ React</li><li>ESLint: ตรวจจับความผิดพลาดเชิงตรรกะในโค็ด</li></ul></li><li><p>ส่วนหลัง (Backend)</p><ul><li>Node.js: รันไทม์สำหรับภาษาโปรแกรม JavaScript</li><li>TypeScript: ภาษาเพิ่มเติมจาก JavaScript ที่ช่วยจับข้อผิดพลาดผ่าน Type-Checking และ Interface</li><li>Express: ระบบจัดการเชื่อมต่อระหว่างผู้ใช้บน HTTP/HTTPS</li><li>Express RateLimit: เพิ่มการจำกัดเข้าถึงทรัพยากรบนเซิร์ฟเวอร์ด้วยช่วงเวลา</li><li>Cors: เพิ่มการจำกัดเข้าถึงทรัพยากรบนเซิร์ฟเวอร์กับผู้ใช้บางส่วน</li><li>Compression: เพิ่มการบีบอัดข้อมูลระหว่างการเชื่อมต่อกับเซิร์ฟเวอร์</li><li>ESLint: ตรวจจับความผิดพลาดเชิงตรรกะในโค็ด</li><li>Nodemon: อำนวยความสำดวกในการพัฒนาระบบ</li></ul></li><li><p>ส่วนข้อมูล (Database)</p><ul><li>MySQL: สำหรับการจัดเก็บข้อมูลผู้ใช้, ข้อมูลสินค้า, ข้อมูลชำระเงิน, ข้อมูลจัดส่ง, ประวัติ, และรวมไปถึงกิจกรรมระบบ</li><li>Redis: สำหรับการแคชข้อมูลที่ใช้งานบ่อยเพื่อเพิ่มประสิทธิภาพระบบ</li></ul></li><li><p>ส่วนออกแบบ (Design Tool)</p><ul><li>Draw.io: ใช้งานสำหรับการเขียนวาดภาพไดอะแกรม Use Cases Diagram, Sequences Diagram</li></ul></li></ul><h2 id="แนวทางการทดสอบ-testing-approach" tabindex="-1">แนวทางการทดสอบ (Testing Approach) <a class="header-anchor" href="#แนวทางการทดสอบ-testing-approach" aria-label="Permalink to &quot;แนวทางการทดสอบ (Testing Approach)&quot;">​</a></h2><p>ประเภทการทดสอบ (Testing Types)</p><ul><li>[ ] Unit Testing</li><li>[ ] Functional Testing</li><li>[ ] API Testing</li><li>[ ] Performance Testing</li><li>[ ] Security Testing</li><li>[ ] User Acceptance Testing (UAT)</li></ul><p>เครื่องมือที่ใช้ (Tools)</p><ul><li>[ ] Postman</li><li>[ ] JMeter</li><li>[ ] Selenium</li><li>[ ] Robot Framework</li><li>[ ] Appium</li><li>[ ] อื่น ๆ</li></ul><p>(ประโยคตัวอย่างรายละเอียด)</p><ul><li>(ประโยคตัวอย่าง)</li><li>(ประโยคตัวอย่าง)</li><li>(ประโยคตัวอย่าง)</li><li>(ประโยคตัวอย่าง)</li></ul><h2 id="ผลลัพธ์ที่คาดว่าจะได้รับ-expected-outcomes" tabindex="-1">ผลลัพธ์ที่คาดว่าจะได้รับ (Expected Outcomes) <a class="header-anchor" href="#ผลลัพธ์ที่คาดว่าจะได้รับ-expected-outcomes" aria-label="Permalink to &quot;ผลลัพธ์ที่คาดว่าจะได้รับ (Expected Outcomes)&quot;">​</a></h2><p>(ประโยคตัวอย่าง)</p><ul><li>ประโยชน์ที่ 1: (ประโยคตัวอย่าง)</li><li>ประโยชน์ที่ 2: (ประโยคตัวอย่าง)</li><li>ประโยชน์ที่ 3: (ประโยคตัวอย่าง)</li><li>ประโยชน์ที่ 4: (ประโยคตัวอย่าง)</li></ul><h2 id="แผนการดําเนินงาน-4-สัปดาห์-work-plan-4-weeks" tabindex="-1">แผนการดำเนินงาน 4 สัปดาห์ (Work Plan: 4 Weeks) <a class="header-anchor" href="#แผนการดําเนินงาน-4-สัปดาห์-work-plan-4-weeks" aria-label="Permalink to &quot;แผนการดำเนินงาน 4 สัปดาห์ (Work Plan: 4 Weeks)&quot;">​</a></h2><p><em>(ประโยคตัวอย่าง)</em></p><h3 id="สัปดาห์ที่-1-วิเคราะห์และออกแบบระบบ-analysis-design" tabindex="-1">สัปดาห์ที่ 1: วิเคราะห์และออกแบบระบบ (Analysis &amp; Design) <a class="header-anchor" href="#สัปดาห์ที่-1-วิเคราะห์และออกแบบระบบ-analysis-design" aria-label="Permalink to &quot;สัปดาห์ที่ 1: วิเคราะห์และออกแบบระบบ (Analysis &amp; Design)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="สัปดาห์ที่-2-พัฒนา-frontend-frontend-development" tabindex="-1">สัปดาห์ที่ 2: พัฒนา Frontend (Frontend Development) <a class="header-anchor" href="#สัปดาห์ที่-2-พัฒนา-frontend-frontend-development" aria-label="Permalink to &quot;สัปดาห์ที่ 2: พัฒนา Frontend (Frontend Development)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="สัปดาห์ที่-3-พัฒนา-backend-และฐานข้อมูล-backend-database-development" tabindex="-1">สัปดาห์ที่ 3: พัฒนา Backend และฐานข้อมูล (Backend &amp; Database Development) <a class="header-anchor" href="#สัปดาห์ที่-3-พัฒนา-backend-และฐานข้อมูล-backend-database-development" aria-label="Permalink to &quot;สัปดาห์ที่ 3: พัฒนา Backend และฐานข้อมูล (Backend &amp; Database Development)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h3 id="สัปดาห์ที่-4-ทดสอบระบบและนําเสนอ-testing-presentation" tabindex="-1">สัปดาห์ที่ 4: ทดสอบระบบและนำเสนอ (Testing &amp; Presentation) <a class="header-anchor" href="#สัปดาห์ที่-4-ทดสอบระบบและนําเสนอ-testing-presentation" aria-label="Permalink to &quot;สัปดาห์ที่ 4: ทดสอบระบบและนำเสนอ (Testing &amp; Presentation)&quot;">​</a></h3><p><em>(ประโยคตัวอย่างรายละเอียดโดยย่อ)</em></p><h2 id="แผนภาพ" tabindex="-1">แผนภาพ <a class="header-anchor" href="#แผนภาพ" aria-label="Permalink to &quot;แผนภาพ&quot;">​</a></h2><h3 id="use-case-diagram" tabindex="-1">Use Case Diagram <a class="header-anchor" href="#use-case-diagram" aria-label="Permalink to &quot;Use Case Diagram&quot;">​</a></h3><p><img src="'+r+'" alt="Use Case Diagram"></p><h3 id="class-diagram" tabindex="-1">Class Diagram <a class="header-anchor" href="#class-diagram" aria-label="Permalink to &quot;Class Diagram&quot;">​</a></h3><p><img src="'+e+'" alt="Class Diagram"></p><h3 id="sequence-diagram" tabindex="-1">Sequence Diagram <a class="header-anchor" href="#sequence-diagram" aria-label="Permalink to &quot;Sequence Diagram&quot;">​</a></h3><p><img src="'+e+'" alt="Sequence Diagram"></p><h3 id="wireframe" tabindex="-1">Wireframe <a class="header-anchor" href="#wireframe" aria-label="Permalink to &quot;Wireframe&quot;">​</a></h3><p><img src="'+e+'" alt="Wireframe"></p><h3 id="prototype" tabindex="-1">Prototype <a class="header-anchor" href="#prototype" aria-label="Permalink to &quot;Prototype&quot;">​</a></h3><p><img src="'+e+'" alt="Prototype"></p>',64)])])}const q=i(s,[["render",m]]);export{g as __pageData,q as default};
